import { existsSync, readFileSync } from "node:fs"
import { resolve } from "node:path"

import { defineConfig } from "drizzle-kit"

const envPath = resolve(".env")
if (existsSync(envPath)) {
  const content = readFileSync(envPath, "utf-8")
  for (const line of content.split("\n")) {
    const match = line.match(/^([A-Z_][A-Z0-9_]*)=(.*)$/)
    if (match && !process.env[match[1]]) {
      process.env[match[1]] = match[2].replace(/^["']|["']$/g, "")
    }
  }
}

const databaseUrl = process.env.DATABASE_URL
if (!databaseUrl) {
  throw new Error(
    "Missing DATABASE_URL env var required for Drizzle Kit. " +
      "Set it in .env or your shell before running db:* scripts.",
  )
}

export default defineConfig({
  schema: "./shared/db/schema/index.ts",
  out: "./drizzle",
  dialect: "postgresql",
  dbCredentials: { url: databaseUrl },
  casing: "snake_case",
  verbose: true,
  strict: true,
})
---server/utils/db---
import { drizzle, type PostgresJsDatabase } from "drizzle-orm/postgres-js"
import postgres from "postgres"
import * as schema from "~~/shared/db/schema"

type Db = PostgresJsDatabase<typeof schema>

let _client: ReturnType<typeof postgres> | undefined
let _db: Db | undefined

export function useDb(): Db {
  if (_db) return _db
  const url = process.env.DATABASE_URL
  if (!url) throw new Error("DATABASE_URL is not set")
  _client = postgres(url, {
    max: 10,
    idle_timeout: 20,
    connect_timeout: 10,
    ...(process.env.NODE_ENV === "production" ? { ssl: "require" as const } : {}),
  })
  _db = drizzle(_client, { schema, casing: "snake_case" })
  return _db
}

export async function closeDb(): Promise<void> {
  if (_client) {
    await _client.end()
    _client = undefined
    _db = undefined
  }
}

