import { defineConfig } from "vitest/config"
import tsconfigPaths from "vite-tsconfig-paths"

// Integration suite. Runs `tests/integration/**/*.test.ts` against PGlite —
// the same Postgres dialect as production, in-process, no Docker. Kept
// separate from the main Vitest config so `bun run test` stays fast (PGlite
// boot + migrations is ~250ms per setup); CI runs both.
export default defineConfig({
  plugins: [tsconfigPaths()],
  test: {
    environment: "node",
    globals: false,
    include: ["tests/integration/**/*.test.ts"],
    exclude: ["node_modules", ".nuxt", ".output"],
    // PGlite is a singleton-style WASM instance per test file; running suites
    // in parallel risks cross-test interference if a future helper goes
    // global. Serial keeps the picture simple and the cost is small.
    fileParallelism: false,
  },
})

