import { z } from "zod"
import { inngest } from "../inngest"
import { publishVersion, VersionStateError } from "../extensions-state"

const eventDataSchema = z.object({ versionId: z.string().min(1) })

export const reindexSearch = inngest.createFunction(
  {
    id: "reindex-search",
    triggers: [{ event: "extension/index.requested" }],
  },
  async ({ event, step }) => {
    const parsed = eventDataSchema.safeParse(event.data)
    if (!parsed.success) {
      console.error("[reindex-search] invalid event payload", parsed.error)
      return { ok: false, reason: "invalid_event" }
    }
    const { versionId } = parsed.data

    let extensionId: string
    try {
      const result = await step.run("publish-version", () => publishVersion(versionId))
      extensionId = result.extensionId
    } catch (err) {
      if (err instanceof VersionStateError) {
        return { ok: false, reason: err.code }
      }
      throw err
    }

    // Nuxt's data layer caches via useFetch keys, not tags. Cache busting on
    // the consuming page happens via re-fetch when the user navigates back.
    // No revalidateTag equivalent needed here.

    await step.sendEvent("notify-published", {
      name: "extension/published",
      data: { extensionId, versionId },
    })

    return { ok: true, extensionId }
  },
)

import {
  countFilteredExtensions,
  listExtensions,
} from "~~/server/utils/queries/extensions"
import {
  parseFilters,
  searchParamsToInput,
} from "~~/shared/validators/filters"

export default defineEventHandler(async (event) => {
  const url = getRequestURL(event)
  const filters = parseFilters({
    ...searchParamsToInput(url.searchParams),
    dept: "__all",
  })

  try {
    const [items, total] = await Promise.all([
      listExtensions(filters),
      countFilteredExtensions(filters),
    ])

    setHeader(
      event,
      "Cache-Control",
      "public, s-maxage=60, stale-while-revalidate=300",
    )

    return {
      items: items.map((ext) => ({
        slug: ext.slug,
        name: ext.name,
        nameZh: ext.nameZh,
        category: ext.category,
        scope: ext.scope,
        badge: ext.badge,
        description: ext.description,
        descriptionZh: ext.descriptionZh,
        tags: ext.tagIds,
        funcCat: ext.funcCat,
        subCat: ext.subCat,
        l2: ext.l2,
        downloadsCount: ext.downloadsCount,
        starsAvg: ext.starsAvg != null ? Number(ext.starsAvg).toFixed(1) : "0.0",
      })),
      total,
      page: filters.page,
      pageSize: 24,
    }
  } catch (err) {
    console.error("[api/v1/extensions] db error:", err)
    apiError(event, "Failed to fetch extensions.", 500, "server_error")
  }
})

import { getExtensionBySlug } from "~~/server/utils/queries/extension-detail"

export default defineEventHandler(async (event) => {
  const slug = getRouterParam(event, "slug")
  if (!slug) apiError(event, "slug required", 400, "invalid_request")

  try {
    const ext = await getExtensionBySlug(slug)
    if (!ext) apiError(event, "Extension not found.", 404, "not_found")

    setHeader(
      event,
      "Cache-Control",
      "public, s-maxage=60, stale-while-revalidate=300",
    )

    return {
      slug: ext.slug,
      name: ext.name,
      nameZh: ext.nameZh,
      category: ext.category,
      scope: ext.scope,
      badge: ext.badge,
      tagline: ext.tagline,
      description: ext.description,
      descriptionZh: ext.descriptionZh,
      tags: ext.tagIds,
      funcCat: ext.funcCat,
      subCat: ext.subCat,
      l2: ext.l2,
      license: ext.licenseSpdx,
      homepageUrl: ext.homepageUrl,
      repoUrl: ext.repoUrl,
      compatibilityJson: ext.compatibilityJson,
      downloadsCount: ext.downloadsCount,
      starsAvg: ext.starsAvg != null ? Number(ext.starsAvg).toFixed(1) : "0.0",
      ratingsCount: ext.ratingsCount,
      publishedAt: ext.publishedAt,
      version: "latest",
      bundleUrl: `/api/v1/extensions/${ext.slug}/bundle`,
    }
  } catch (err) {
    if (err && typeof err === "object" && "statusCode" in err) throw err
    console.error("[api/v1/extensions/:slug] db error:", err)
    apiError(event, "Failed to fetch extension.", 500, "server_error")
