    .innerJoin(files, eq(files.id, extensionVersions.bundleFileId))
    .innerJoin(extensions, eq(extensions.id, extensionVersions.extensionId))
    .where(
      and(eq(extensions.slug, slug), eq(extensionVersions.status, "ready")),
