  status: VersionStatus
  publishedAt?: Date | null
}

export async function updateStatus(
  db: Transactable,
  versionId: string,
  payload: VersionStatusUpdate,
): Promise<void> {
  await db
    .update(extensionVersions)
    .set(payload)
    .where(eq(extensionVersions.id, versionId))
