import { and, eq } from "drizzle-orm"
import { collectionItems, collections } from "~~/shared/db/schema/collection"

export async function getOrCreateSystemCollection(
  userId: string,
  kind: "installed" | "saved",
): Promise<string> {
  const db = useDb()
  const existing = await db
    .select({ id: collections.id })
    .from(collections)
    .where(
      and(eq(collections.ownerUserId, userId), eq(collections.systemKind, kind)),
    )
    .limit(1)
  if (existing[0]) return existing[0].id

  const id = crypto.randomUUID()
  await db.insert(collections).values({
    id,
    ownerUserId: userId,
    name: kind === "installed" ? "Installed" : "Saved",
    systemKind: kind,
  })
  return id
}

export async function upsertCollectionItem(collectionId: string, extensionId: string) {
  const db = useDb()
  await db
    .insert(collectionItems)
    .values({ collectionId, extensionId })
    .onConflictDoNothing()
}

export async function getUserCollections(userId: string) {
  const db = useDb()
  return db
    .select({
      id: collections.id,
      name: collections.name,
      systemKind: collections.systemKind,
    })
    .from(collections)
    .where(eq(collections.ownerUserId, userId))
    .orderBy(collections.createdAt)
}

import {
  index,
  integer,
  pgEnum,
  pgTable,
  text,
  timestamp,
  unique,
} from "drizzle-orm/pg-core";

import { users } from "./auth";
import { extensions } from "./extension";

export const installSourceEnum = pgEnum("install_source", ["cli", "web"]);

export const installs = pgTable(
  "installs",
  {
    id: text().primaryKey(),
    userId: text()
      .notNull()
      .references(() => users.id, { onDelete: "cascade" }),
    extensionId: text()
      .notNull()
      .references(() => extensions.id, { onDelete: "cascade" }),
    version: text().notNull(),
    source: installSourceEnum().notNull(),
    installedAt: timestamp({ withTimezone: true }).notNull().defaultNow(),
    uninstalledAt: timestamp({ withTimezone: true }),
  },
  (t) => [index("idx_installs_user_ext").on(t.userId, t.extensionId)],
);

export const ratings = pgTable(
  "ratings",
  {
    id: text().primaryKey(),
    userId: text()
      .notNull()
      .references(() => users.id, { onDelete: "cascade" }),
    extensionId: text()
      .notNull()
      .references(() => extensions.id, { onDelete: "cascade" }),
    stars: integer().notNull(),
    review: text(),
    createdAt: timestamp({ withTimezone: true }).notNull().defaultNow(),
  },
  (t) => [unique("rating_user_ext").on(t.userId, t.extensionId)],
);

import {
  pgEnum,
  pgTable,
  primaryKey,
  text,
  timestamp,
} from "drizzle-orm/pg-core";

import { users } from "./auth";
import { extensions } from "./extension";

export const systemKindEnum = pgEnum("system_kind", ["installed", "saved"]);

export const collections = pgTable("collections", {
  id: text().primaryKey(),
  ownerUserId: text()
    .notNull()
    .references(() => users.id, { onDelete: "cascade" }),
  name: text().notNull(),
  nameZh: text(),
  // null for user-created groups; non-null for the auto-managed Installed/Saved
  systemKind: systemKindEnum(),
  createdAt: timestamp({ withTimezone: true }).notNull().defaultNow(),
});

export const collectionItems = pgTable(
  "collection_items",
  {
    collectionId: text()
      .notNull()
      .references(() => collections.id, { onDelete: "cascade" }),
    extensionId: text()
      .notNull()
      .references(() => extensions.id, { onDelete: "cascade" }),
    addedAt: timestamp({ withTimezone: true }).notNull().defaultNow(),
  },
  (t) => [primaryKey({ columns: [t.collectionId, t.extensionId] })],
);

