// @vitest-environment nuxt
import { mockNuxtImport } from "@nuxt/test-utils/runtime"
import { beforeEach, describe, expect, it, vi } from "vitest"
import { ref } from "vue"

import { useFilters } from "./useFilters"

const routeQuery = ref<Record<string, string | string[] | undefined>>({})
const routePath = ref("/en/extensions")

mockNuxtImport("useRoute", () => () => ({
  query: routeQuery.value,
  path: routePath.value,
}))

const routerReplace = vi.fn()
mockNuxtImport("useRouter", () => () => ({
  replace: routerReplace,
}))

mockNuxtImport("useLocalePath", () => () => (p: string) => `/en${p}`)

beforeEach(() => {
  routeQuery.value = {}
  routePath.value = "/en/extensions"
  routerReplace.mockReset()
})

describe("useFilters — parse", () => {
  it("returns the empty-filter default for an empty query", () => {
    const { filters } = useFilters()
    expect(filters.value).toEqual({})
  })

  it("parses single-value query params (category, sort)", () => {
    routeQuery.value = { category: "skills", sort: "recent" }
    const { filters } = useFilters()
    expect(filters.value.category).toBe("skills")
    expect(filters.value.sort).toBe("recent")
  })

  it("parses array-valued tags from repeated query keys", () => {
    routeQuery.value = { tags: ["search", "api"] }
    const { filters } = useFilters()
    expect(filters.value.tags).toEqual(["search", "api"])
  })

  it("drops null array elements (vue-router quirk on partially-cleared params)", () => {
    routeQuery.value = { tags: ["a", null as unknown as string] }
    const { filters } = useFilters()
    expect(filters.value.tags).toEqual(["a"])
  })
})

describe("useFilters — update", () => {
  it("calls router.replace with the new query string", () => {
    const { update } = useFilters()
    update({ q: "kubernetes" })
    expect(routerReplace).toHaveBeenCalledWith(
      expect.stringMatching(/^\/en\/extensions\?.*q=kubernetes/),
    )
  })

  it("resets page when the update doesn't include `page`", () => {
    routeQuery.value = { page: "5" }
    const { update } = useFilters()
    update({ q: "foo" })
    const target = routerReplace.mock.calls[0]?.[0] as string
    expect(target).not.toMatch(/page=/)
  })

  it("preserves the explicit page when `page` is in the update", () => {
    const { update } = useFilters()
    update({ q: "foo", page: 3 })
    const target = routerReplace.mock.calls[0]?.[0] as string
    expect(target).toMatch(/page=3/)
  })

  it("emits just the path with no trailing `?` when the query becomes empty", () => {
    routeQuery.value = { q: "foo" }
    const { update } = useFilters()
    update({ q: undefined })
    expect(routerReplace).toHaveBeenCalledWith("/en/extensions")
  })
})

describe("useFilters — hrefForFilters", () => {
  it("prefixes the locale path via useLocalePath and applies the partial filter", () => {
    const { hrefForFilters } = useFilters()
    const href = hrefForFilters({ category: "skills" })
    expect(href).toBe("/en/extensions?category=skills")
  })

  it("resets page when the partial doesn't include `page`", () => {
    routeQuery.value = { page: "9" }
    const { hrefForFilters } = useFilters()
    const href = hrefForFilters({ category: "mcp" })
    expect(href).not.toMatch(/page=/)
  })

  it("accepts a custom basePath argument", () => {
    const { hrefForFilters } = useFilters()
    const href = hrefForFilters({ category: "skills" }, "/collections")
    expect(href.startsWith("/en/collections")).toBe(true)
  })
})

